import React from 'react';
import CartItem from '../components/CartItem';
import { useCart } from '../hooks/useCart';

const CartPage = () => {
  const { cartItems, updateQuantity, removeItem } = useCart();

  return (
    <div className="max-w-6xl mx-auto px-4 py-8">
      <h1 className="text-3xl font-bold mb-6">Shopping Cart</h1>
      {cartItems.length === 0 ? (
        <p className="text-gray-400">Your cart is empty. Start adding some fruits!</p>
      ) : (
        <div>
          {cartItems.map(item => (
            <CartItem key={item.id} item={item} updateQuantity={updateQuantity} removeItem={removeItem} />
          ))}
          <div className="mt-6">
            <button className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition">
              Proceed to Checkout
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default CartPage;
